import React, { useState } from "react";

const CreateCategory = ({ isOpen, onClose, onCreate, onGoBack }) => {
  const [categoryName, setCategoryName] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    if (categoryName.trim()) {
      onCreate(categoryName);
      setCategoryName("");
      onClose();
    }
  };

  return (
    <div className="task-categories-page">
      <div className="task-border">
        <div className="categories-card">
          <div className="categories-main-header">
            <h2>Task Categories</h2>
            <button className="go-back-link" onClick={onGoBack}>
              Go Back
            </button>
          </div>
          <div className="modal-overlay">
            <div className="modal-content card">
              <form onSubmit={handleSubmit}>
                <div className="form-group">
                  <label htmlFor="categoryName" className="input-label">
                    Category Name
                  </label>
                  <input
                    type="text"
                    id="categoryName"
                    className="modal-input"
                    value={categoryName}
                    onChange={(e) => setCategoryName(e.target.value)}
                    autoFocus
                  />
                </div>

                <div className="modal-actions">
                  <button type="submit" className="btn-modal btn-create">
                    Create
                  </button>
                  <button
                    type="button"
                    className="btn-modal btn-cancel"
                    onClick={onClose}
                  >
                    Cancel
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CreateCategory;
